# =========================
#     Constantes / Regex
# =========================

PMC_PREFIXES = [
    "PMC", "PEB", "PGE", "PGA", "DQF", "PRA", "PAG", "PUB",
    "MPC", "AKH", "QKE", "AKE", "PYB", "AAD",
    "P1P", "PIP", "PAJ", "HMJ", "RAP"
]

PMC_PATTERN = re.compile(
    rf"^(?:BULK|(?:({'|'.join(map(re.escape, PMC_PREFIXES))})[A-Z0-9]+|PLA\d+[A-Z0-9]*))$"
)

IATA_PAIR = re.compile(r"\b([A-Z]{3})\s*-\s*([A-Z]{3})\b")

HEADER_EXCLUDE = re.compile(
    r"(Flight No\./Date|Point of Loading|Arr\. Date|Import Check Manifest|\*[A-Z0-9\-]+)"
)


# =========================
#   Logo Break & Build PDF
# =========================
BREAKBUILD_LOGO_BASE64 = """"""


def _logo_bytes_io():
    import base64
    return io.BytesIO(base64.b64decode(BREAKBUILD_LOGO_BASE64))


def _parse_number_fr(value):
    txt = str(value or "0").strip().replace(" ", "").replace(",", ".")
    try:
        return float(txt)
    except:
        return 0.0


def _format_number_fr(value, decimals=2):
    try:
        number = float(value)
    except:
        number = 0.0
    txt = f"{number:,.{decimals}f}"
    return txt.replace(",", " ").replace(".", ",")


def _format_multiline_kg_fr(value, decimals=2):
    """Formate une cellule poids simple ou multi-lignes en gardant une ligne par AWB."""
    parts = []
    for item in str(value or "").split("\n"):
        item = item.strip()
        if not item:
            continue
        parts.append(_format_number_fr(_parse_number_fr(item), decimals))
    return "\n".join(parts)


def _br(text):
    return str(text or "").replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;").replace("\n", "<br/>")


def _draw_bottom_line(canvas, doc):
    # Les cover sheets ne doivent pas avoir de ligne décorative en pied de page.
    if getattr(canvas, "_skip_bottom_line", False):
        return

    red = colors.HexColor("#E30613")
    y = 18
    x1 = doc.leftMargin + 5
    x2 = A4[0] - doc.rightMargin - 5
    mid = (x1 + x2) / 2
    canvas.saveState()
    canvas.setLineWidth(1.3)
    canvas.setStrokeColor(red)
    canvas.line(x1, y, mid - 30, y)
    canvas.setStrokeColor(colors.black)
    canvas.line(mid - 30, y, mid + 30, y)
    canvas.setStrokeColor(red)
    canvas.line(mid + 30, y, x2, y)
    canvas.restoreState()


class _DisableBottomLineFromNextPage(Flowable):
    """Active un flag canvas avant le saut de page vers les cover sheets."""
    def wrap(self, availWidth, availHeight):
        return 0, 0

    def draw(self):
        self.canv._skip_bottom_line = True


def _title_html(title):
    safe = str(title).replace("&", "&amp;").replace("<", "&lt;").replace(">", "&gt;")
    return "<b>" + safe.replace(" - RESUME", " - <font color='#E30613'>RESUME</font>") + "</b>"



def _build_awb_total_pcs_map(dataframe):
    """Construit AWB -> total PCS, puis trie les cover sheets par PCS AWB croissant."""
    awb_totals = {}
    if dataframe is None or dataframe.empty:
        return awb_totals

    # Pour Excel, "PCS sur PMC par AWB" donne les PCS réellement présents sur chaque PMC.
    # Pour PDF manifest, cette colonne n'existe pas : on utilise "Pièces par AWB".
    pcs_column = "PCS sur PMC par AWB" if "PCS sur PMC par AWB" in dataframe.columns else "Pièces par AWB"

    for _, row in dataframe.iterrows():
        awbs = [a.strip() for a in str(row.get("Liste des AWB", "") or "").split("\n")]
        pcs_values = [p.strip() for p in str(row.get(pcs_column, "") or "").split("\n")]

        for idx, awb in enumerate(awbs):
            if not awb:
                continue
            pcs_raw = pcs_values[idx] if idx < len(pcs_values) else "0"
            try:
                pcs_val = int(float(str(pcs_raw).replace(" ", "").replace(",", ".").split("/")[0]))
            except:
                pcs_val = 0
            awb_totals[awb] = awb_totals.get(awb, 0) + pcs_val

    # IMPORTANT : l'ordre du dict est conserve par Python.
    # Les cover sheets utilisent ensuite awb_totals.items(), donc ce tri definit
    # directement l'ordre des pages AWB dans le PDF.
    # Tri principal : total PCS AWB croissant. Tri secondaire : numero AWB.
    return dict(sorted(awb_totals.items(), key=lambda item: (item[1], item[0])))


def _append_awb_cover_sheets(story, dataframe, start_with_page_break=True):
    """Ajoute les cover sheets AWB à la suite du PDF résumé Excel.

    Une page par AWB, avec 3 blocs larges et bien centrés :
    AWB / NB. PCS. / NB. SKIDS.
    """
    awb_totals = _build_awb_total_pcs_map(dataframe)
    if not awb_totals:
        return

    styles = getSampleStyleSheet()
    header_style = ParagraphStyle(
        "CoverHeaderLarge",
        parent=styles["Normal"],
        fontName="Helvetica-Bold",
        fontSize=31,
        leading=35,
        alignment=TA_CENTER,
        textColor=colors.black,
        wordWrap="CJK",
    )
    value_style = ParagraphStyle(
        "CoverValueLarge",
        parent=styles["Normal"],
        fontName="Helvetica-Bold",
        fontSize=40,
        leading=44,
        alignment=TA_CENTER,
        textColor=colors.black,
        wordWrap="CJK",
    )

    if start_with_page_break:
        # À partir des cover sheets, on retire la ligne décorative en pied de page.
        story.append(_DisableBottomLineFromNextPage())
        story.append(PageBreak())

    for page_idx, (awb, pcs) in enumerate(awb_totals.items()):
        if page_idx > 0:
            story.append(PageBreak())

        # Centrage vertical des 3 blocs sur la page.
        story.append(Spacer(1, 98))

        rows = [
            [Paragraph("AWB", header_style)],
            [Paragraph(str(awb), value_style)],
            [""],
            [Paragraph("NB. PCS.", header_style)],
            [Paragraph(str(int(pcs)), value_style)],
            [""],
            [Paragraph("NB. SKIDS", header_style)],
            [Paragraph("", value_style)],
        ]

        table = Table(
            rows,
            colWidths=[430],
            rowHeights=[72, 98, 38, 72, 92, 38, 72, 92],
            hAlign="CENTER",
        )
        table.setStyle(TableStyle([
            ("BACKGROUND", (0, 0), (0, 0), colors.HexColor("#D0D0D0")),
            ("BACKGROUND", (0, 3), (0, 3), colors.HexColor("#D0D0D0")),
            ("BACKGROUND", (0, 6), (0, 6), colors.HexColor("#D0D0D0")),
            ("BOX", (0, 0), (0, 1), 1.5, colors.black),
            ("BOX", (0, 3), (0, 4), 1.5, colors.black),
            ("BOX", (0, 6), (0, 7), 1.5, colors.black),
            ("LINEBELOW", (0, 0), (0, 0), 1.5, colors.black),
            ("LINEBELOW", (0, 3), (0, 3), 1.5, colors.black),
            ("LINEBELOW", (0, 6), (0, 6), 1.5, colors.black),
            ("ALIGN", (0, 0), (-1, -1), "CENTER"),
            ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
            ("TOPPADDING", (0, 0), (-1, -1), 0),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 0),
            ("LEFTPADDING", (0, 0), (-1, -1), 2),
            ("RIGHTPADDING", (0, 0), (-1, -1), 2),
        ]))
        story.append(table)

def generate_awb_cover_sheets_pdf(dataframe, file_name="manifest"):
    """Ancien export séparé conservé en helper, mais plus affiché dans Streamlit."""
    buffer = io.BytesIO()
    doc = SimpleDocTemplate(
        buffer,
        pagesize=A4,
        leftMargin=36,
        rightMargin=36,
        topMargin=36,
        bottomMargin=36,
    )
    story = []
    _append_awb_cover_sheets(story, dataframe, start_with_page_break=False)
    doc.build(story)
    pdf = buffer.getvalue()
    buffer.close()
    return pdf


