def _format_breakdown_number(value):
    """Format court pour le breakdown : 1581 au lieu de 1 581,00 si entier."""
    number = _parse_number_fr(value)
    if abs(number - int(number)) < 0.00001:
        return str(int(number))
    return _format_number_fr(number, 1)


def _append_pmc_breakdown_sheets(story, dataframe, start_with_page_break=True):
    """Ajoute une page breakdown individuelle par PMC.

    Format demandé :
    - aucune entête, aucun logo ;
    - bloc N° / BREAKDOWN ;
    - tableau AWB / PCS / POIDS (KG) + ligne TOTAL ;
    - contenu centré et lisible sur la page.
    """
    if dataframe is None or dataframe.empty:
        return

    if start_with_page_break:
        story.append(PageBreak())

    styles = getSampleStyleSheet()
    big_style = ParagraphStyle(
        "BreakdownBig",
        parent=styles["Normal"],
        fontName="Helvetica-Bold",
        fontSize=20,
        leading=24,
        alignment=TA_CENTER,
        textColor=colors.black,
        wordWrap="CJK",
    )
    header_style = ParagraphStyle(
        "BreakdownHeader",
        parent=big_style,
        fontSize=18,
        leading=22,
    )
    cell_style = ParagraphStyle(
        "BreakdownCell",
        parent=big_style,
        fontSize=18,
        leading=22,
    )

    grey = colors.HexColor("#D0D0D0")

    for idx, (_, row) in enumerate(dataframe.reset_index(drop=True).iterrows(), start=1):
        if idx > 1:
            story.append(PageBreak())

        # Placement validé : gros espace haut pour centrer le bloc dans la page.
        story.append(Spacer(1, 188))

        pmc = str(row.get("PMC No", "") or "").strip()

        top_table = Table(
            [
                [Paragraph("N°", header_style), Paragraph("BREAKDOWN", header_style)],
                [Paragraph(str(idx), cell_style), Paragraph(_br(pmc), cell_style)],
            ],
            colWidths=[92, 300],
            rowHeights=[42, 44],
            hAlign="CENTER",
        )
        top_table.setStyle(TableStyle([
            ("GRID", (0, 0), (-1, -1), 2.0, colors.black),
            ("BACKGROUND", (0, 0), (-1, 0), grey),
            ("ALIGN", (0, 0), (-1, -1), "CENTER"),
            ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
            ("TOPPADDING", (0, 0), (-1, -1), 0),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 0),
            ("LEFTPADDING", (0, 0), (-1, -1), 3),
            ("RIGHTPADDING", (0, 0), (-1, -1), 3),
        ]))
        story.append(top_table)
        story.append(Spacer(1, 58))

        pcs_column = "PCS sur PMC par AWB" if "PCS sur PMC par AWB" in dataframe.columns else "Pièces par AWB"
        awbs = [x.strip() for x in str(row.get("Liste des AWB", "") or "").split("\n") if x.strip()]
        pcs_values = [x.strip() for x in str(row.get(pcs_column, "") or "").split("\n") if x.strip()]
        kg_values = [x.strip() for x in str(row.get("Poids par AWB", "") or "").split("\n") if x.strip()]

        detail_rows = [[
            Paragraph("AWB", header_style),
            Paragraph("PCS", header_style),
            Paragraph("POIDS (KG)", header_style),
        ]]

        total_pcs = 0
        total_kg = 0.0
        for line_idx, awb in enumerate(awbs):
            pcs_raw = pcs_values[line_idx] if line_idx < len(pcs_values) else "0"
            kg_raw = kg_values[line_idx] if line_idx < len(kg_values) else "0"
            try:
                pcs_val = int(float(str(pcs_raw).replace(" ", "").replace(",", ".").split("/")[0]))
            except:
                pcs_val = 0
            kg_val = _parse_number_fr(kg_raw)
            total_pcs += pcs_val
            total_kg += kg_val
            detail_rows.append([
                Paragraph(_br(awb), cell_style),
                Paragraph(str(pcs_val), cell_style),
                Paragraph(_format_breakdown_number(kg_val), cell_style),
            ])

        if not awbs:
            total_pcs = int(row.get("Total Pièces", 0) or 0)
            total_kg = _parse_number_fr(row.get("Poids brut (kg)", 0))

        # On garde le total officiel de la ligne si disponible.
        total_pcs = int(row.get("Total Pièces", total_pcs) or total_pcs)
        total_kg = _parse_number_fr(row.get("Poids brut (kg)", total_kg) or total_kg)

        detail_rows.append([
            Paragraph("TOTAL", header_style),
            Paragraph(str(total_pcs), cell_style),
            Paragraph(_format_breakdown_number(total_kg), cell_style),
        ])

        detail_table = Table(
            detail_rows,
            colWidths=[190, 100, 150],
            rowHeights=[42] + [42] * (len(detail_rows) - 1),
            hAlign="CENTER",
        )
        detail_table.setStyle(TableStyle([
            ("GRID", (0, 0), (-1, -1), 2.0, colors.black),
            ("BACKGROUND", (0, 0), (-1, 0), grey),
            ("BACKGROUND", (0, len(detail_rows) - 1), (-1, len(detail_rows) - 1), grey),
            ("ALIGN", (0, 0), (-1, -1), "CENTER"),
            ("VALIGN", (0, 0), (-1, -1), "MIDDLE"),
            ("TOPPADDING", (0, 0), (-1, -1), 0),
            ("BOTTOMPADDING", (0, 0), (-1, -1), 0),
            ("LEFTPADDING", (0, 0), (-1, -1), 3),
            ("RIGHTPADDING", (0, 0), (-1, -1), 3),
        ]))
        story.append(detail_table)

