def _build_v6_header_story(file_name, dataframe):
    """Construit l'entête V6 Break & Build utilisé par les PDF Excel et PDF manifest."""
    total_pmc = int(dataframe["PMC No"].nunique()) if not dataframe.empty and "PMC No" in dataframe.columns else 0
    total_pcs = int(dataframe["Total Pièces"].astype(int).sum()) if not dataframe.empty and "Total Pièces" in dataframe.columns else 0
    total_kg = sum(_parse_number_fr(v) for v in dataframe.get("Poids brut (kg)", [])) if not dataframe.empty else 0.0

    unique_awb = set()
    if not dataframe.empty:
        for awb_cell in dataframe.get("Liste des AWB", []):
            for awb in str(awb_cell or "").split("\n"):
                awb = awb.strip()
                if awb:
                    unique_awb.add(awb)
    total_awb = len(unique_awb)

    clean_file_name = os.path.splitext(str(file_name or "manifest"))[0]
    title = f"{clean_file_name} - RESUME"

    styles = getSampleStyleSheet()
