#        Salaires
# =========================
SALARY_IBAN_MAP = {
    "BASSIROU SEIBOU MOUSTAPHA": "BE92001986281023",
    "WEGNEZ RAPHAEL JOEL B": "BE11340132658248",
    "ILBAY BAYRAM": "BE32001410399602",
    "TUZZOLINO MARCO": "BE61363131568517",
    "EL KHOUMSI ABDEL ALI": "BE10950196247604",
    "FU QING YUAN": "FR7630004023220000044125444",
}


def _salary_match_key(value):
    """Normalise fortement un texte pour comparer les noms extraits du PDF."""
    import unicodedata
    value = unicodedata.normalize("NFKD", str(value or ""))
    value = "".join(ch for ch in value if not unicodedata.combining(ch))
    value = value.upper()
    value = re.sub(r"[^A-Z]+", " ", value)
    value = re.sub(r"\s+", " ", value).strip()
    return value


def _salary_name_variants(name):
    """Retourne NOM PRENOM et PRENOM NOM pour matcher les deux écritures."""
    key = _salary_match_key(name)
    parts = [p for p in key.split() if p]
    variants = {key}
    if len(parts) >= 2:
        variants.add(" ".join(reversed(parts)))
    return variants


def _find_salary_identity(text, source_name=""):
    """Retrouve le salarié dans le texte PDF ou dans le nom du fichier.

    Le PDF Securex peut extraire le nom sous plusieurs formes :
    - ILBAY BAYRAM
    - Monsieur ILBAY BAYRAM
    - BAYRAM ILBAY
    - parfois seulement dans le nom du fichier.
    """
    search_blob = _salary_match_key(f"{text}\n{source_name}")
    search_words = set(search_blob.split())

    # 1) Match exact d'un des noms connus, dans les deux sens.
    for mapped_name, iban in SALARY_IBAN_MAP.items():
        for variant in _salary_name_variants(mapped_name):
            if variant and variant in search_blob:
                return mapped_name, iban

    # 2) Match par mots : utile si le PDF insère des caractères ou des sauts de ligne.
    for mapped_name, iban in SALARY_IBAN_MAP.items():
        name_words = set(_salary_match_key(mapped_name).split())
        if name_words and name_words.issubset(search_words):
            return mapped_name, iban

    # 3) Fallback : extraire ce qui suit Monsieur/Madame puis comparer au mapping.
    flat_text = _salary_match_key(text)
    match = re.search(
        r"(?:MONSIEUR|MADAME)\s+([A-Z ]{3,80}?)(?=\s+(?:RUE|AVENUE|CHAUSSEE|BOULEVARD|QUAI|PLACE|DATE|NATIONALITE|EMPLOYE|CELIBATAIRE|DIVORCE|$))",
        flat_text,
        flags=re.IGNORECASE,
    )
    if match:
        candidate = _salary_match_key(match.group(1))
        candidate_words = set(candidate.split())
        for mapped_name, iban in SALARY_IBAN_MAP.items():
            for variant in _salary_name_variants(mapped_name):
                if candidate == variant or variant in candidate:
                    return mapped_name, iban
            mapped_words = set(_salary_match_key(mapped_name).split())
            if mapped_words and mapped_words.issubset(candidate_words):
                return mapped_name, iban
        return candidate.title(), ""

    return "", ""


def _format_amount_eur_fr(amount_text):
    amount_text = str(amount_text or "").strip().replace(" ", "").replace(".", "")
    amount_text = amount_text.replace(",", ".")
    try:
        amount = float(amount_text)
    except:
        amount = 0.0
    return _format_number_fr(amount, 2) + " €"


def _extract_salary_text_from_pdf(uploaded_pdf):
    pdf_bytes = uploaded_pdf.read()
    with fitz.open(stream=pdf_bytes, filetype="pdf") as doc:
        pages = []
        for page in doc:
            pages.append(page.get_text("text"))
    return "\n".join(pages)


def _extract_salary_row_from_text(text, source_name=""):
    text = str(text or "")
    clean = re.sub(r"[ \t]+", " ", text)

    name, iban = _find_salary_identity(text, source_name)

    # Montant : ligne "*** Net à payer" / "*** Net Â payer".
    net_match = re.search(r"([0-9][0-9\.\s]*,\d{2})\s+\*{3}\s+Net", clean, flags=re.IGNORECASE)
    net_amount = _format_amount_eur_fr(net_match.group(1)) if net_match else ""

    # Période salariale : on utilise le mois de début de période, ex. 01.05.2026 => 05/2026.
    period_match = re.search(
        r"P.riode\s+salariale\s+(\d{2})\.(\d{2})\.(\d{4})\s*-\s*(\d{2})\.(\d{2})\.(\d{4})",
        clean,
        flags=re.IGNORECASE,
    )
    if period_match:
        month_year = f"{period_match.group(2)}/{period_match.group(3)}"
    else:
        month_year = ""

    acompte_detecte = bool(re.search(r"\bAcompte\b", clean, flags=re.IGNORECASE))
    prefix = "Solde salaire" if acompte_detecte else "Salaire"
    communication = f"{prefix} {month_year}".strip()

    status = "OK"
    notes = []
    if not name:
        notes.append("Nom non trouvé")
    if not iban:
        notes.append("Compte non trouvé dans le mapping")
    if not net_amount:
        notes.append("Net à payer non trouvé")
    if not month_year:
        notes.append("Période salariale non trouvée")
    if notes:
        status = " / ".join(notes)

    display_name = " ".join(part.capitalize() for part in _salary_match_key(name).split()) if name else ""

    return {
        "Nom": display_name,
        "Compte": iban,
        "Montant": net_amount,
        "Communication": communication,
        "Statut": status,
        "Fichier": source_name,
    }


def extract_salary_rows_from_pdfs(uploaded_pdfs):
    rows = []
    for uploaded_pdf in uploaded_pdfs or []:
        try:
            text = _extract_salary_text_from_pdf(uploaded_pdf)
            rows.append(_extract_salary_row_from_text(text, uploaded_pdf.name))
        except Exception as exc:
            rows.append({
                "Nom": "",
                "Compte": "",
                "Montant": "",
                "Communication": "",
                "Statut": f"Erreur lecture PDF : {exc}",
                "Fichier": getattr(uploaded_pdf, "name", ""),
            })
    return pd.DataFrame(rows)


def _salary_excel_bytes(dataframe):
    buffer = io.BytesIO()
    with pd.ExcelWriter(buffer, engine="openpyxl") as writer:
        dataframe.to_excel(writer, index=False, sheet_name="Salaires")
    buffer.seek(0)
    return buffer.getvalue()

